#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>
#include <cuda_runtime.h>

#define NTX 16
#define NTY 16

double stop_watch(double t0)
{
  double time;
  struct timeval t;
  gettimeofday(&t, NULL);
  time = t.tv_sec * 1e6 + t.tv_usec;
  return time - t0;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

void reference(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  for (int y = 0; y < Ly; y++) {
    for (int x = 0; x < Lx; x++) {
      int v00 = y * Lx + x;
      int v0p = y * Lx + (x + 1) % Lx;
      int v0m = y * Lx + (Lx + x - 1) % Lx;
      int vp0 = ((y + 1) % Ly) * Lx + x;
      int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
      out[v00] = norm * in[v00] + delta * (in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

__global__ void dev_lapl_iter_kernel(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  int x = blockIdx.x * blockDim.x + threadIdx.x;
  int y = blockIdx.y * blockDim.y + threadIdx.y;

  if (x < Lx && y < Ly) {
    int v00 = y * Lx + x;
    int v0p = y * Lx + (x + 1) % Lx;
    int v0m = y * Lx + (Lx + x - 1) % Lx;
    int vp0 = ((y + 1) % Ly) * Lx + x;
    int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
    out[v00] = norm * in[v00] + delta * (in[v0p] + in[v0m] + in[vp0] + in[vm0]);
  }
}

void dev_lapl_iter(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  dim3 block(NTX, NTY);
  dim3 grid((Lx + NTX - 1) / NTX, (Ly + NTY - 1) / NTY);
  dev_lapl_iter_kernel<<<grid, block>>>(out, in, delta, norm, Lx, Ly);
}

int main(int argc, char *argv[]) {

  if (argc != 4) {
    usage(argv);
    exit(1);
  }

  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 || Ly % NTY != 0) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
           NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);

  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f + 4.0f * sigma);
  const float xnorm = 1.0f / (1.0f + 4.0f * sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);

  srand(123);
  float *buffer = (float*) malloc(sizeof(float) * Lx * Ly);
  float *h_out = (float*) malloc(sizeof(float) * Lx * Ly);
  float *h_in  = (float*) malloc(sizeof(float) * Lx * Ly);

  int i, j, x, y;
  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; j < Ly; j++)
      buffer[x + j * Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; j < Lx; j++)
      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float) * Lx * Ly);

  for (i = 0; i < niter; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  float *d_out = (float*) malloc(sizeof(float) * Lx * Ly);
  float *d_in  = (float*) malloc(sizeof(float) * Lx * Ly);
  memcpy(d_in, buffer, sizeof(float) * Lx * Ly);

  float *d_out_dev = NULL;
  float *d_in_dev = NULL;
  cudaMalloc((void**)&d_in_dev, sizeof(float) * Lx * Ly);
  cudaMalloc((void**)&d_out_dev, sizeof(float) * Lx * Ly);
  cudaMemcpy(d_in_dev, d_in, sizeof(float) * Lx * Ly, cudaMemcpyHostToDevice);

  double t0;
  t0 = stop_watch(0);
  for (i = 0; i < niter; i++) {
    dev_lapl_iter(d_out_dev, d_in_dev, xdelta, xnorm, Lx, Ly);
    std::swap(d_out_dev, d_in_dev);
  }
  cudaDeviceSynchronize();
  t0 = stop_watch(t0) / (double)niter;

  cudaMemcpy(d_in, d_in_dev, sizeof(float) * Lx * Ly, cudaMemcpyDeviceToHost);

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
         niter, Lx, Ly, t0,
         Lx * Ly * sizeof(float) * 2.0 / (t0 * 1.0e3),
         (Lx * Ly * 6.0) / (t0 * 1.0e3));

  bool ok = true;
  for (i = 0; i < Lx * Ly; i++) {
    if (fabs(h_in[i] - d_in[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_in[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(buffer);
  free(h_out);
  free(h_in);
  free(d_in);
  free(d_out);
  cudaFree(d_in_dev);
  cudaFree(d_out_dev);
  return 0;
}
